// 辅助函数：将int64切片转换为string切片
func convertInt64SliceToString1D(slice []int64) []string {
	if slice == nil {
		return nil
	}
	result := make([]string, len(slice))
	for i, v := range slice {
		result[i] = strconv.FormatInt(v, 10)
	}
	return result
}

func convertInt64SliceToString2D(slice [][]int64) [][]string {
	if slice == nil {
		return nil
	}
	result := make([][]string, len(slice))
	for i, v := range slice {
		result[i] = convertInt64SliceToString1D(v)
	}
	return result
}

func convertInt64SliceToString3D(slice [][][]int64) [][][]string {
	if slice == nil {
		return nil
	}
	result := make([][][]string, len(slice))
	for i, v := range slice {
		result[i] = convertInt64SliceToString2D(v)
	}
	return result
}
